    34→/**
    35→ * Write text to the terminal.
    36→ * This is util because console.log is async
    37→ * @param value
    38→ * @param output
    39→ */
    40→export function logSync(
    41→  value: string,
    42→  output: 'stdout' | 'stderr' | 'warning' = 'stdout',
    43→) {
    44→  let formatted = value.endsWith('\n') ? value : value + '\n';
    45→  if (output === 'stderr') formatted = chalk.red(formatted);
    46→  if (output === 'warning') {
    47→    formatted = chalk.bgBlackBright(chalk.yellow(formatted));
    48→  }
    49→  const channel = output === 'warning' ? 'stdout' : output;
    50→  fs.writeSync(process[channel].fd, formatted);
    51→}
