    53→export function escapeRegExp(string: string) {
    54→  return (
    55→    string
    56→      // https://github.com/sindresorhus/escape-string-regexp/blob/main/index.js
    57→      .replace(/[|\\{}()[\]^$+*?.]/g, '\\$&')
    58→      .replace(/-/g, '\\x2d')
    59→  );
    60→}
    61→
    62→// https://stackoverflow.com/a/7616484
    63→export function hashString(str: string) {
    64→  if (str.length === 0) return '0';
    65→  let hash = 0;
    66→  for (let i = 0; i < str.length; i++) {
    67→    const char = str.charCodeAt(i);
    68→    hash = (hash << 5) - hash + char;
    69→    hash |= 0;
    70→  }
    71→  return hash.toString(36).replace(/^-/, '');
    72→}
    73→
    74→// Throw an error if the valor is falsy
    75→export function invariant(
    76→  value: unknown,
    77→  error = 'Expected value to not be empty.',
    78→): asserts value {
    79→  if (!value) throw new Error(error);
    80→}
    81→
    82→export function lastElement<T>(parts: T[]): T {
    83→  invariant(parts.length, 'Expected array to not be empty');
    84→  return parts[parts.length - 1];
    85→}
