    87→// Search on files to imports matching a specific string
    88→export namespace DiscoveryUsedImports {
    89→  export type Params = {
    90→    // the root folder to be scanned
    91→    folder: string;
    92→    // glob import declarations to be included
    93→    match: string[];
    94→    // glob imports to be ignored
    95→    ignore?: string[];
    96→  };
    97→
    98→  export function find(params: Params): string[] {
    99→    const { folder } = params;
   100→    const resolvedFolder = path.resolve(folder);
   101→    const filePaths = glob.sync(`${resolvedFolder}/**/*.{ts,tsx}`);
   102→    const elements = new Set<string>();
   103→
   104→    const testImport = createMatcher(params);
   105→
   106→    for (const filePath of filePaths) {
   107→      const fileContent = fs.readFileSync(filePath, 'utf8');
   108→
   109→      const sourceFile = ts.createSourceFile(
   110→        filePath,
   111→        fileContent,
   112→        ts.ScriptTarget.Latest,
   113→        true,
   114→      );
   115→
   116→      function visit(node: ts.Node) {
   117→        const specifier = ts.isImportDeclaration(node)
   118→          ? ts.isStringLiteral(node.moduleSpecifier)
   119→            ? node.moduleSpecifier.text
   120→            : null
   121→          : null;
   122→        if (testImport(specifier)) elements.add(specifier);
   123→        ts.forEachChild(node, visit);
   124→      }
   125→
   126→      visit(sourceFile);
   127→    }
   128→
   129→    return [...elements];
   130→  }
   131→}
