   133→// Creates a tester function from a glob pattern
   134→export function createMatcher(params: {
   135→  match: string | string[];
   136→  ignore?: string | string[];
   137→}) {
   138→  type NullableString = string | null | undefined;
   139→
   140→  function getPattern(glob: string) {
   141→    assertString(glob);
   142→
   143→    let regexString = '';
   144→    let i = 0;
   145→    let segment = '';
   146→
   147→    while (i < glob.length) {
   148→      const char = glob[i];
   149→
   150→      if (char === '*') {
   151→        if (segment) {
   152→          regexString += escapeRegExp(segment);
   153→          segment = '';
   154→        }
   155→
   156→        if (glob[i + 1] === '*') {
   157→          // Here, the current char is '*' and the next one is '*', then
   158→          // it is '**': match everything including slashes
   159→          regexString += '.*';
   160→          i += 2;
   161→        } else {
   162→          regexString += '[^/]*';
   163→          i++;
   164→        }
   165→      } else {
   166→        segment += char;
   167→        i++;
   168→      }
   169→    }
   170→
   171→    if (segment) {
   172→      regexString += escapeRegExp(segment);
   173→    }
   174→
   175→    return regexString;
   176→  }
   177→
   178→  function getTest(glob: NullableString | NullableString[]) {
   179→    let array = (Array.isArray(glob) ? glob : [glob]).filter(Boolean);
   180→    if (!array || !array.length) return () => false;
   181→    const pattern = array.map(glob => getPattern(glob!)).join('|');
   182→    const regex = new RegExp(`^${pattern}$`);
   183→    return function test(value: NullableString) {
   184→      if (typeof value !== 'string') return false;
   185→      return regex.test(value);
   186→    };
   187→  }
   188→
   189→  const testInclude = getTest(params.match);
   190→  const testExclude = getTest(params.ignore);
   191→
   192→  return function test(value: NullableString): value is string {
   193→    if (typeof value !== 'string') return false;
   194→    return testInclude(value) && !testExclude(value);
   195→  };
   196→}
   197→
   198→export function assertString(
   199→  value: unknown,
   200→  message?: string,
   201→): asserts value is string {
   202→  invariant(
   203→    'string' === typeof value,
   204→    message ?? `Expected value to be a string.; found ${typeof value} instead.`,
   205→  );
   206→}
