   208→// Compare package versions between appSemPararv3 and our local package
   209→export namespace PackageVersionCheck {
   210→  export type PackageInfo = {
   211→    superAppVersion: string;
   212→    localVersion: string | null;
   213→    packageName: string;
   214→    isRemoteVersionNewer: boolean;
   215→    isLocalVersionNewer: boolean;
   216→    areDifferent: boolean;
   217→  };
   218→
   219→  export function init() {
   220→    const { SUPER_APP_PATH } = ScriptConfig;
   221→
   222→    const superAppPackageJSON = fs.readJSONSync(
   223→      path.resolve(SUPER_APP_PATH, 'package.json'),
   224→    ) as ScriptConfig.PackageJSON;
   225→
   226→    const localPackages = {
   227→      ...ScriptConfig.packageJSON.dependencies,
   228→      ...ScriptConfig.packageJSON.devDependencies,
   229→    };
   230→
   231→    const superAppPackages = {
   232→      ...superAppPackageJSON.dependencies,
   233→      ...superAppPackageJSON.devDependencies,
   234→    };
   235→
   236→    const notInSyncVersions = new Map<string, PackageInfo>();
   237→
   238→    const cleanVersion = (version: string) => version.replace(/^\D+/g, '');
   239→
   240→    function check(packageName: string): PackageInfo | null {
   241→      const superAppVersion = superAppPackages[packageName];
   242→      const localVersion = localPackages[packageName];
   243→
   244→      const bothHave = Boolean(superAppVersion && localVersion);
   245→
   246→      const areDifferent =
   247→        bothHave &&
   248→        superAppVersion.replace(/[\D.]/g, '') !==
   249→          localVersion.replace(/[\D.]/g, '');
   250→
   251→      const isLocalVersionNewer =
   252→        areDifferent &&
   253→        isVersionGreater(
   254→          cleanVersion(localVersion),
   255→          cleanVersion(superAppVersion),
   256→        );
   257→
   258→      const isRemoteVersionNewer =
   259→        areDifferent &&
   260→        isVersionGreater(
   261→          cleanVersion(superAppVersion),
   262→          cleanVersion(localVersion),
   263→        );
   264→
   265→      const checked: PackageInfo = {
   266→        localVersion,
   267→        packageName,
   268→        superAppVersion,
   269→        isRemoteVersionNewer,
   270→        isLocalVersionNewer,
   271→        areDifferent,
   272→      };
   273→
   274→      if (areDifferent) {
   275→        notInSyncVersions.set(packageName, checked);
   276→      }
   277→      return checked;
   278→    }
   279→
   280→    function getWarnings() {
   281→      const versions = [...notInSyncVersions.values()];
   282→
   283→      const outdated = versions.filter(el => el.isRemoteVersionNewer);
   284→      const newer = versions.filter(el => el.isLocalVersionNewer);
   285→
   286→      if (!outdated.length && !newer.length) return;
   287→
   288→      const greenVersion = (version: string) =>
   289→        chalk.bgGreen.greenBright(version);
   290→      const redVersion = (version: string) => chalk.bgRed.bgRedBright(version);
   291→
   292→      let text = chalk.yellow(
   293→        '‣ The following packages may be updated to match' +
   294→          ' the versions used by appSemPararv3:\n',
   295→      );
   296→
   297→      const tab = '   ';
   298→
   299→      if (newer.length) {
   300→        text += `\n🟡 These local versions are conflicting (newer) with the ones on appSemPararv3:\n`;
   301→        newer.forEach(value => {
   302→          text +=
   303→            tab +
   304→            `${value.packageName}@${redVersion(value.localVersion!)}${greenVersion(value.superAppVersion)}\n`;
   305→        });
   306→      }
   307→
   308→      if (outdated.length) {
   309→        text += `\n🟡 Sync outdated packages with appSemPararv3:\n`;
   310→        text += 'npm install \\\n';
   311→
   312→        const lastIndex = outdated.length - 1;
   313→
   314→        outdated.forEach((item, idx) => {
   315→          const suffix = idx === lastIndex ? '' : ' \\';
   316→          text +=
   317→            tab +
   318→            `'${item.packageName}@${greenVersion(item.superAppVersion)}'${suffix}\n`;
   319→        });
   320→      }
   321→
   322→      if (newer.length && outdated.length) {
   323→        text +=
   324→          '\n' +
   325→          chalk.bgYellow.yellowBright(` △ There are 2 warnings above △ `);
   326→      }
   327→
   328→      return text;
   329→    }
   330→
   331→    return {
   332→      check,
   333→      getWarnings,
   334→      outdatedPackages: notInSyncVersions,
   335→    };
   336→  }
   337→}
