     2→/**
     3→ * Format eslint results listing by severity
     4→ * @param results
     5→ * @returns {string}
     6→ */
     7→const chalk = require('chalk');
     8→
     9→module.exports = function (results) {
    10→  const warnings = [];
    11→  const errors = [];
    12→
    13→  results.forEach(result => {
    14→    const { filePath, messages } = result;
    15→    messages.forEach(message => {
    16→      const line = message.line || 0;
    17→      const column = message.column || 0;
    18→      const entry = {
    19→        filePath,
    20→        line,
    21→        column,
    22→        ruleId: message.ruleId,
    23→        message: message.message,
    24→      };
    25→
    26→      if (message.severity === 1) {
    27→        // severity 1 === 'warn'
    28→        warnings.push(entry);
    29→      } else if (message.severity === 2) {
    30→        // severity 2 === 'error'
    31→        errors.push(entry);
    32→      }
    33→    });
    34→  });
    35→
    36→  let output = '';
    37→  let totalProblems = 0;
    38→
    39→  if (warnings.length > 0) {
    40→    output += `\n${chalk.yellow('[ESLINT WARNINGS]')}\n`;
    41→    warnings.forEach(w => {
    42→      output += `  ${chalk.yellow('Warning')}: ${w.message} (${w.ruleId})\n`;
    43→      output += `  ${chalk.gray(`at ${w.filePath}:${w.line}:${w.column}`)}\n\n`;
    44→    });
    45→    totalProblems += warnings.length;
    46→  }
    47→
    48→  if (errors.length > 0) {
    49→    output += `\n${chalk.red('[ESLINT ERRORS]')}\n`;
    50→    errors.forEach(e => {
    51→      output += `  ${chalk.red('Error')}: ${e.message} (${e.ruleId})\n`;
    52→      output += `  ${chalk.gray(`at ${e.filePath}:${e.line}:${e.column}`)}\n\n`;
    53→    });
    54→    totalProblems += errors.length;
    55→  }
    56→
    57→  if (totalProblems > 0) {
    58→    output += `\n${chalk.bold.red(`✖ ${totalProblems} problems (${errors.length} errors, ${warnings.length} warnings)`)}\n`;
    59→  } else {
    60→    output += `\n${chalk.bold.green('✔ No problems found!')}\n`;
    61→  }
    62→
    63→  return output;
    64→};
